    const getGuideContent = () => {
        switch (tutorialStep) {
            case 'EVENT_TRIGGERED':
                return {
                    title: "A New Beginning",
                    text: "Your forge is in ruins. Follow the prompt to visit the market and begin rebuilding.",
                    target: null
                };
            case 'MARKET_BUY_FURNACE':
                return {
                    title: "Essential Equipment",
                    text: "Click on the Furnace to add it to your shopping cart.",
                    target: "furnace-item"
                };
