                return {
                    title: "Finalize Purchase",
                    text: "You have enough gold. Click 'Pay Now' to install the Furnace.",
                    target: "market-pay-btn"
                };
            case 'GO_BACK_FORGE':
                return {
                    title: "Return to Forge",
                    text: "Installation complete! Go back to the Forge tab to start your first project.",
                    target: "tab-FORGE"
                };
            case 'SELECT_BRONZE_SWORD':
