import React, { useState, useEffect } from 'react';
import { useGame } from '../context/GameContext';
import { MousePointer2, ChevronRight, Sparkles, X } from 'lucide-react';

const TutorialOverlay: React.FC = () => {
    const { state } = useGame();
    const { tutorialStep } = state;

    // 현재 단계의 안내창 노출 여부 관리
    const [isVisible, setIsVisible] = useState(false);
    const [lastStep, setLastStep] = useState('');

    // 튜토리얼 단계가 변경될 때마다 안내창을 다시 띄움
    useEffect(() => {
        if (tutorialStep !== 'NONE' && tutorialStep !== lastStep) {
            setIsVisible(true);
            setLastStep(tutorialStep);

            // 8초 후 자동 소멸 (사용자가 읽기에 충분한 시간)
            const timer = setTimeout(() => {
                setIsVisible(false);
            }, 8000);

            return () => clearTimeout(timer);
        }
    }, [tutorialStep, lastStep]);

    if (tutorialStep === 'NONE') return null;

    const getGuideContent = () => {
        switch (tutorialStep) {
            case 'EVENT_TRIGGERED':
                return {
                    title: "The Forge lies in Ruins",
                    text: "Your journey starts with a single spark. To begin forging, you must first install a Furnace from the market.",
                    target: "tab-MARKET"
                };
            case 'MARKET_BUY_FURNACE':
                return {
                    title: "Essential Equipment",
                    text: "Click on the Furnace to add it to your shopping cart.",
                    target: "furnace-item"
                };
            case 'MARKET_PAY_NOW':
                return {
                    title: "Finalize Purchase",
                    text: "You have enough gold. Click 'Pay Now' to install the Furnace.",
                    target: "market-pay-btn"
                };
            case 'GO_BACK_FORGE':
                return {
                    title: "Return to Forge",
                    text: "Installation complete! Go back to the Forge tab to start your first project.",
                    target: "tab-FORGE"
                };
            case 'SELECT_BRONZE_SWORD':
                return {
                    title: "Select a Recipe",
                    text: "Pick the Bronze Shortsword. It's a reliable blade for any adventurer.",
                    target: "sword_bronze_t1-item"
                };
            case 'PRESS_START_FORGING':
                return {
                    title: "Ignite the Fire",
                    text: "You have the materials. Click 'Start Forging' to enter the smithing chamber.",
                    target: "start-forging-btn"
                };
            case 'MINIGAME_PRESS_HEAT':
                return {
                    title: "Master the Heat",
                    text: "The metal is cold. Press the 'HEAT' button once to add fuel.",
                    target: "minigame-heat-btn"
                };
            case 'MINIGAME_WAIT_TEMP':
                return {
                    title: "Patience is Key",
                    text: "Wait for the temperature to cool down to 450°C.",
                    target: "temp-gauge"
                };
            case 'MINIGAME_PRESS_BELLOWS':
                return {
                    title: "Stoke the Flames",
                    text: "Temperature is dropping too low! Rapidly press the 'PUMP' (Bellows) until the heat reaches its peak!",
                    target: "minigame-bellows-btn"
                };
            case 'MINIGAME_TAP_TO_START':
                return {
                    title: "Strike while hot",
                    text: "The metal is glowing! Tap anywhere on the screen to begin smithing.",
                    target: null
                };
            default:
                return null;
        }
    };

    const content = getGuideContent();
    if (!content || !isVisible) return null;

    return (
        <div className="fixed inset-0 z-[4000] pointer-events-none overflow-hidden select-none">
            {/* 안내 상자 컨테이너 */}
            <div 
                className={`absolute left-1/2 bottom-32 md:bottom-auto md:top-1/4 -translate-x-1/2 w-[85%] max-w-sm bg-stone-900 border-2 border-amber-500 rounded-2xl shadow-[0_0_50px_rgba(0,0,0,0.8)] p-5 md:p-7 flex flex-col items-center text-center animate-in slide-in-from-top-8 fade-in duration-500 pointer-events-auto cursor-pointer group active:scale-95 transition-transform`}
                onClick={() => setIsVisible(false)} // 클릭 시 즉시 닫힘
            >
                {/* 닫기 버튼 아이콘 */}
                <div className="absolute top-3 right-3 text-stone-600 group-hover:text-stone-400">
                    <X className="w-4 h-4" />
                </div>

                <div className="bg-amber-900/30 p-2 rounded-xl border border-amber-700/50 mb-3 md:mb-4">
                    <Sparkles className="w-6 h-6 text-amber-500 animate-pulse" />
                </div>

                <h3 className="text-lg md:text-xl font-black text-amber-100 font-serif uppercase tracking-tight mb-2">
                    {content.title}
                </h3>

                <p className="text-stone-300 text-xs md:text-base leading-relaxed mb-4 italic">
                    "{content.text}"
                </p>

                <div className="flex items-center gap-2 text-stone-500 font-black uppercase text-[9px] tracking-widest opacity-60">
                    <span>Click message to dismiss</span>
                    <ChevronRight className="w-3 h-3" />
                </div>

                {/* 대상 가이드 포인터 (안내창이 떴을 때만 표시) */}
                {content.target && (
                    <div className="absolute -bottom-12 md:-bottom-16 left-1/2 -translate-x-1/2 animate-bounce pointer-events-none">
                        <MousePointer2 className="w-8 h-8 md:w-10 md:h-10 text-amber-400 drop-shadow-[0_0_10px_rgba(245,158,11,0.8)] fill-amber-500/20" />
                    </div>
                )}
            </div>
        </div>
    );
};

