import EventModal from './modals/EventModal';
import SleepModal from './modals/SleepModal';
import JournalModal from './modals/JournalModal';
import DungeonResultModal from './modals/DungeonResultModal';
import CraftingResultModal from './modals/CraftingResultModal';
import SettingsModal from './modals/SettingsModal';
import TutorialOverlay from './TutorialOverlay';

interface MainGameLayoutProps {
    onQuit: () => void;
    onLoadFromSettings: (data: any, index: number) => void;
}

const MainGameLayout: React.FC<MainGameLayoutProps> = ({ onQuit, onLoadFromSettings }) => {
  const [activeTab, setActiveTab] = useState<'FORGE' | 'INVENTORY' | 'MARKET' | 'SHOP' | 'TAVERN' | 'DUNGEON' | 'SIMULATION'>('FORGE');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const { state, actions } = useGame();

  // Tutorial Auto-Navigation
  useEffect(() => {
    if (state.tutorialStep === 'MARKET_BUY_FURNACE' && activeTab !== 'MARKET') {
        setActiveTab('MARKET');
    } else if (state.tutorialStep === 'EVENT_TRIGGERED' && activeTab === 'MARKET') {
        // Automatically advance to MARKET_BUY_FURNACE once user clicks market
        actions.setTutorialStep('MARKET_BUY_FURNACE');
    }
  }, [state.tutorialStep, activeTab, actions]);

  // Scroll visibility logic
  const scrollRef = useRef<HTMLDivElement>(null);
  const [showLeftArrow, setShowLeftArrow] = useState(false);
  const [showRightArrow, setShowRightArrow] = useState(false);

  const updateArrows = useCallback(() => {
    if (scrollRef.current) {
      const { scrollLeft, scrollWidth, clientWidth } = scrollRef.current;
      const canScroll = scrollWidth > clientWidth + 2;
      setShowLeftArrow(canScroll && scrollLeft > 1);
      const isAtEnd = Math.ceil(scrollLeft) >= (scrollWidth - clientWidth - 2);
      setShowRightArrow(canScroll && !isAtEnd);
    }
  }, []);

  const scrollTabs = (direction: 'LEFT' | 'RIGHT') => {
    if (scrollRef.current) {
      const amount = direction === 'LEFT' ? -200 : 200;
      scrollRef.current.scrollBy({ left: amount, behavior: 'smooth' });
    }
  };

  useLayoutEffect(() => {
    const timer = setTimeout(updateArrows, 100);
    return () => clearTimeout(timer);
  }, [updateArrows, activeTab]);

  useEffect(() => {
    window.addEventListener('resize', updateArrows);
    return () => window.removeEventListener('resize', updateArrows);
  }, [updateArrows]);

  useShopService();
  useDungeonService();

  const completedExpeditionsCount = state.activeExpeditions.filter(
      exp => exp.status === 'COMPLETED'
  ).length;

  const totalShopVisitors = (state.activeCustomer ? 1 : 0) + state.shopQueue.length;
  const isFullscreenOverlay = state.isCrafting || (state.activeManualDungeon && state.showManualDungeonOverlay);

  const renderTabButton = (id: typeof activeTab, Icon: any, label: string, badgeCount: number = 0) => {
    const isActive = activeTab === id;
    const isTutorialTarget = (state.tutorialStep === 'GO_BACK_FORGE' && id === 'FORGE') || 
                            (state.tutorialStep === 'EVENT_TRIGGERED' && id === 'MARKET');

    return (
        <button 
            id={`tab-${id}`}
            onClick={() => setActiveTab(id)}
            className={`relative flex items-center gap-2 px-5 md:px-6 py-3 md:py-4 border-b-2 transition-all whitespace-nowrap snap-start shrink-0 ${
                isActive 
                ? 'border-amber-500 text-amber-500 bg-stone-800/60 z-10' 
                : 'border-transparent text-stone-500 hover:text-stone-300 hover:bg-stone-800/30'
            } ${isTutorialTarget ? 'ring-2 ring-amber-500 animate-pulse bg-amber-900/20' : ''}`}
        >
            <Icon className={`w-4 h-4 md:w-5 md:h-5 ${isActive ? 'scale-110' : ''}`} />
            <span className="font-bold tracking-wide text-[10px] md:text-sm uppercase">{label}</span>
            {badgeCount > 0 && (
                <div className="absolute top-1 right-1 flex h-4 w-4 md:h-5 md:w-5 items-center justify-center rounded-full bg-red-600 text-[8px] md:text-[10px] font-black text-white shadow-lg ring-2 ring-stone-900 animate-in zoom-in">
                    {badgeCount}
                </div>
            )}
        </button>
    );
  };

  return (
    <div className="h-[100dvh] w-full bg-stone-950 text-stone-200 flex flex-col overflow-hidden font-sans selection:bg-amber-500/30 animate-in fade-in duration-500 px-safe">

      <div className={`flex flex-col shrink-0 z-30 transition-all duration-500 ease-in-out ${isFullscreenOverlay ? '-translate-y-full h-0 opacity-0 pointer-events-none' : 'translate-y-0 h-auto opacity-100'}`}>
        <Header 
          activeTab={activeTab} 
          onTabChange={setActiveTab} 
          onSettingsClick={() => setIsSettingsOpen(true)}
        />

        <div className="bg-stone-900 border-b border-stone-800 flex items-center relative z-10 overflow-hidden isolate h-11 md:h-14">

          <div 
            className={`absolute left-0 top-0 bottom-0 z-30 w-12 flex items-center transition-all duration-300 transform-gpu ${
                showLeftArrow ? 'opacity-100 scale-100 visible pointer-events-auto' : 'opacity-0 scale-0 invisible pointer-events-none'
            }`}
          >
              <div className="absolute inset-0 bg-gradient-to-r from-stone-900 via-stone-900/90 to-transparent" />
              <button onClick={() => scrollTabs('LEFT')} className="relative h-full w-full flex items-center pl-2 group/arrow" aria-label="Scroll Left">
                <ChevronLeft className="w-5 h-5 text-amber-50 group-hover:scale-125 transition-transform" />
              </button>
          </div>

          <div 
            ref={scrollRef}
            onScroll={updateArrows}
            className="flex overflow-x-auto no-scrollbar flex-1 min-w-0 touch-pan-x scroll-smooth snap-x snap-mandatory overscroll-behavior-x-contain"
          >
            {renderTabButton('FORGE', Anvil, 'Forge')}
            {renderTabButton('DUNGEON', MapIcon, 'Dungeon', completedExpeditionsCount)}
            {renderTabButton('INVENTORY', Package, 'Items')}
            {renderTabButton('MARKET', ShoppingBag, 'Market')}
            {renderTabButton('SHOP', Coins, 'Shop', activeTab !== 'SHOP' ? totalShopVisitors : 0)}
            {renderTabButton('TAVERN', Beer, 'Tavern')}
            {renderTabButton('SIMULATION', Activity, 'Sim')}
          </div>

          <div 
            className={`absolute right-0 top-0 bottom-0 z-30 w-12 flex items-center justify-end transition-all duration-300 transform-gpu ${
                showRightArrow ? 'opacity-100 scale-100 visible pointer-events-auto' : 'opacity-0 scale-0 invisible pointer-events-none'
            }`}
          >
              <div className="absolute inset-0 bg-gradient-to-l from-stone-900 via-stone-900/90 to-transparent" />
              <button onClick={() => scrollTabs('RIGHT')} className="relative h-full w-full flex items-center justify-end pr-2 group/arrow" aria-label="Scroll Right">
                <ChevronRight className="w-5 h-5 text-amber-50 group-hover:scale-125 transition-transform" />
              </button>
          </div>
        </div>
      </div>

      <main className="flex-1 overflow-hidden relative bg-stone-925 flex flex-col min-h-0">
        <div className={`h-full w-full ${activeTab === 'FORGE' ? 'block' : 'hidden'}`}>
            <ForgeTab onNavigate={setActiveTab} />
        </div>
        <div className={`h-full w-full ${activeTab === 'SHOP' ? 'block' : 'hidden'}`}>
            <ShopTab onNavigate={setActiveTab} />
        </div>
        {activeTab === 'INVENTORY' && <InventoryDisplay />}
        {activeTab === 'MARKET' && <MarketTab onNavigate={setActiveTab} />}
        {activeTab === 'TAVERN' && <TavernTab />}
        {activeTab === 'DUNGEON' && < DungeonTab />}
        {activeTab === 'SIMULATION' && <SimulationTab />}
      </main>

      {state.toast?.visible && (
        <div onClick={actions.hideToast} className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[3000] flex items-center gap-3 px-6 py-3 bg-stone-900/95 border border-amber-500/50 text-stone-200 rounded-xl shadow-2xl backdrop-blur-md cursor-pointer animate-in slide-in-from-bottom-4 fade-in duration-300 ring-2 ring-black/50 active:scale-95 w-max max-w-[80vw]">
            <Info className="w-5 h-5 text-amber-500 shrink-0" />
            <span className="text-sm font-bold tracking-tight text-center leading-tight">{state.toast.message}</span>
        </div>
      )}

      <div className="h-[env(safe-area-inset-bottom)] bg-stone-900 shrink-0"></div>

      <TutorialOverlay />
      <EventModal />
      <SleepModal />
      <JournalModal />
      <DungeonResultModal />
      <CraftingResultModal />
      <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} onQuit={onQuit} onLoadRequest={onLoadFromSettings} />
    </div>
  );
};

export default MainGameLayout;

import React, { useState, useEffect } from 'react';
import { useGame } from '../context/GameContext';
import { MousePointer2, ChevronRight, Sparkles, X, ScrollText } from 'lucide-react';

const TutorialOverlay: React.FC = () => {
    const { state } = useGame();
    const { tutorialStep } = state;

    const [isVisible, setIsVisible] = useState(false);
    const [lastStep, setLastStep] = useState('');

    useEffect(() => {
        if (tutorialStep !== 'NONE' && tutorialStep !== lastStep) {
            setIsVisible(true);
            setLastStep(tutorialStep);

            // 사용자가 충분히 읽을 수 있도록 서사 단계에서는 시간을 더 길게 설정
            const displayTime = tutorialStep === 'EVENT_TRIGGERED' ? 12000 : 8000;
            const timer = setTimeout(() => {
                setIsVisible(false);
            }, displayTime);

            return () => clearTimeout(timer);
        }
    }, [tutorialStep, lastStep]);

    if (tutorialStep === 'NONE') return null;

    const getGuideContent = () => {
        switch (tutorialStep) {
            case 'EVENT_TRIGGERED':
                return {
                    title: "A Ruined Legacy",
                    text: "You stand amidst the cold ashes of Lockhart's Forge. The fires are out, and the anvil is silent. To restore your family's name, you must first visit the market to secure a new Furnace.",
                    target: "tab-MARKET"
                };
            case 'MARKET_BUY_FURNACE':
                return {
                    title: "Investment for Future",
                    text: "The merchant has a basic Furnace for 500 Gold. Click on it to prepare for installation.",
                    target: "furnace-item"
                };
            case 'MARKET_PAY_NOW':
                return {
                    title: "Finalize Transaction",
                    text: "You have the funds. Click 'Pay Now' to have the equipment delivered to your forge.",
                    target: "market-pay-btn"
                };
            case 'GO_BACK_FORGE':
                return {
                    title: "The Fire Returns",
                    text: "Installation complete! Now, head back to the Forge tab to begin your first project.",
                    target: "tab-FORGE"
                };
            case 'SELECT_BRONZE_SWORD':
                return {
                    title: "Choose a Pattern",
                    text: "Select the Bronze Shortsword recipe. It is the perfect starting point for any master smith.",
                    target: "sword_bronze_t1-item"
                };
            case 'PRESS_START_FORGING':
                return {
                    title: "Ready the Anvil",
                    text: "You have the ores and fuel. Click 'Start Forging' to enter the inner chamber.",
                    target: "start-forging-btn"
                };
            case 'MINIGAME_PRESS_HEAT':
                return {
                    title: "Master the Heat",
                    text: "Metal requires heat to be shaped. Click the 'HEAT' button to stoke the embers.",
                    target: "minigame-heat-btn"
                };
            case 'MINIGAME_WAIT_TEMP':
                return {
                    title: "Observe the Glow",
                    text: "Patience is a virtue. Wait until the metal cools to a workable temperature of 450°C.",
                    target: "temp-gauge"
                };
            case 'MINIGAME_PRESS_BELLOWS':
                return {
                    title: "Keep the Spark Alive",
                    text: "The fire is dying! Rapidly click 'PUMP' to boost the temperature to its peak.",
                    target: "minigame-bellows-btn"
                };
            case 'MINIGAME_TAP_TO_START':
                return {
                    title: "Strike while Hot",
                    text: "The metal glows white! Tap anywhere on the anvil area to begin the rhythm of smithing.",
                    target: null
                };
            default:
                return null;
        }
    };

    const content = getGuideContent();
    if (!content || !isVisible) return null;

    return (
        <div className="fixed inset-0 z-[4000] pointer-events-none overflow-hidden select-none">
            <div 
                className={`absolute left-1/2 bottom-32 md:bottom-auto md:top-1/4 -translate-x-1/2 w-[90%] max-w-sm bg-stone-900 border-2 border-amber-500 rounded-2xl shadow-[0_0_60px_rgba(0,0,0,0.9)] p-6 flex flex-col items-center text-center animate-in slide-in-from-top-8 fade-in duration-500 pointer-events-auto cursor-pointer group active:scale-95 transition-transform`}
                onClick={() => setIsVisible(false)}
            >
                <div className="absolute top-3 right-3 text-stone-600 group-hover:text-stone-400">
                    <X className="w-4 h-4" />
                </div>

                <div className="bg-amber-900/30 p-2.5 rounded-xl border border-amber-700/50 mb-4 shadow-inner">
                    {tutorialStep === 'EVENT_TRIGGERED' ? (
                        <ScrollText className="w-6 h-6 text-amber-500 animate-pulse" />
                    ) : (
                        <Sparkles className="w-6 h-6 text-amber-400 animate-pulse" />
                    )}
                </div>

                <h3 className="text-xl font-black text-amber-100 font-serif uppercase tracking-tight mb-2 drop-shadow-md">
                    {content.title}
                </h3>

                <p className="text-stone-300 text-xs md:text-sm leading-relaxed mb-4 italic px-2">
                    "{content.text}"
                </p>

                <div className="flex items-center gap-2 text-stone-600 font-black uppercase text-[8px] tracking-[0.2em] opacity-80">
                    <span>Dismiss message</span>
                    <ChevronRight className="w-3 h-3" />
                </div>

                {content.target && (
                    <div className="absolute -bottom-14 left-1/2 -translate-x-1/2 animate-bounce pointer-events-none">
                        <MousePointer2 className="w-10 h-10 text-amber-400 drop-shadow-[0_0_15px_rgba(245,158,11,1)] fill-amber-500/20" />
                    </div>
                )}
            </div>
        </div>
    );
};

export default TutorialOverlay;

import React, { useState, useRef, useEffect, useCallback, useLayoutEffect } from 'react';
import Header from './Header';
import { InventoryDisplay } from './InventoryDisplay';
import { Anvil, Package, ShoppingBag, Coins, Beer, Map as MapIcon, Activity, Info, ChevronLeft, ChevronRight } from 'lucide-react';
import { useGame } from '../context/GameContext';

// Import Background Services
import { useShopService } from '../services/shop/shop-service';
import { useDungeonService } from '../services/dungeon/dungeon-service';

// Import Tabs
import ForgeTab from './tabs/Forge/ForgeTab';
import ShopTab from './tabs/Shop/ShopTab';
import TavernTab from './tabs/Tavern/TavernTab';
import MarketTab from './tabs/Market/MarketTab';
import DungeonTab from './tabs/Dungeon/DungeonTab';
import SimulationTab from './tabs/Simulation/SimulationTab';

// Import Modals
import EventModal from './modals/EventModal';
import SleepModal from './modals/SleepModal';
import JournalModal from './modals/JournalModal';
import DungeonResultModal from './modals/DungeonResultModal';
import CraftingResultModal from './modals/CraftingResultModal';
import SettingsModal from './modals/SettingsModal';
import TutorialOverlay from './TutorialOverlay';

interface MainGameLayoutProps {
    onQuit: () => void;
    onLoadFromSettings: (data: any, index: number) => void;
}

const MainGameLayout: React.FC<MainGameLayoutProps> = ({ onQuit, onLoadFromSettings }) => {
  const [activeTab, setActiveTab] = useState<'FORGE' | 'INVENTORY' | 'MARKET' | 'SHOP' | 'TAVERN' | 'DUNGEON' | 'SIMULATION'>('FORGE');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const { state, actions } = useGame();

  const { tutorialStep } = state;

  // Tutorial Auto-Navigation
  useEffect(() => {
    if (tutorialStep === 'MARKET_BUY_FURNACE' && activeTab !== 'MARKET') {
        setActiveTab('MARKET');
    } else if (tutorialStep === 'EVENT_TRIGGERED' && activeTab === 'MARKET') {
        actions.setTutorialStep('MARKET_BUY_FURNACE');
    }
  }, [tutorialStep, activeTab, actions]);

  // Scroll visibility logic
  const scrollRef = useRef<HTMLDivElement>(null);
  const [showLeftArrow, setShowLeftArrow] = useState(false);
  const [showRightArrow, setShowRightArrow] = useState(false);

  const updateArrows = useCallback(() => {
    if (scrollRef.current) {
      const { scrollLeft, scrollWidth, clientWidth } = scrollRef.current;
      const canScroll = scrollWidth > clientWidth + 2;
      setShowLeftArrow(canScroll && scrollLeft > 1);
      const isAtEnd = Math.ceil(scrollLeft) >= (scrollWidth - clientWidth - 2);
      setShowRightArrow(canScroll && !isAtEnd);
    }
  }, []);

  const scrollTabs = (direction: 'LEFT' | 'RIGHT') => {
    if (scrollRef.current) {
      const amount = direction === 'LEFT' ? -200 : 200;
      scrollRef.current.scrollBy({ left: amount, behavior: 'smooth' });
    }
  };

  useLayoutEffect(() => {
    const timer = setTimeout(updateArrows, 100);
    return () => clearTimeout(timer);
  }, [updateArrows, activeTab]);

  useEffect(() => {
    window.addEventListener('resize', updateArrows);
    return () => window.removeEventListener('resize', updateArrows);
  }, [updateArrows]);

  useShopService();
  useDungeonService();

  const completedExpeditionsCount = state.activeExpeditions.filter(
      exp => exp.status === 'COMPLETED'
  ).length;

  const totalShopVisitors = (state.activeCustomer ? 1 : 0) + state.shopQueue.length;
  const isFullscreenOverlay = state.isCrafting || (state.activeManualDungeon && state.showManualDungeonOverlay);

  const renderTabButton = (id: typeof activeTab, Icon: any, label: string, badgeCount: number = 0) => {
    const isActive = activeTab === id;

    // Tutorial Targeting Logic
    const isMarketPhase = ['EVENT_TRIGGERED', 'MARKET_BUY_FURNACE', 'MARKET_PAY_NOW'].includes(tutorialStep);
    const isForgePhase = ['GO_BACK_FORGE', 'SELECT_BRONZE_SWORD', 'PRESS_START_FORGING'].includes(tutorialStep) || tutorialStep.startsWith('MINIGAME_');

    const isTutorialTarget = (isMarketPhase && id === 'MARKET') || (isForgePhase && id === 'FORGE');

    // Disable other tabs during tutorial
    const isTutorialActive = tutorialStep !== 'NONE';
    const isDisabled = isTutorialActive && !isTutorialTarget;

    return (
        <button 
            id={`tab-${id}`}
            onClick={() => !isDisabled && setActiveTab(id)}
            disabled={isDisabled}
            className={`relative flex items-center gap-2 px-5 md:px-6 py-3 md:py-4 border-b-2 transition-all whitespace-nowrap snap-start shrink-0 ${
                isActive 
                ? 'border-amber-500 text-amber-500 bg-stone-800/60 z-10' 
                : 'border-transparent text-stone-500 hover:text-stone-300 hover:bg-stone-800/30'
            } ${isTutorialTarget ? 'ring-2 ring-amber-500 animate-pulse bg-amber-900/20' : ''} ${isDisabled ? 'opacity-30 cursor-not-allowed grayscale' : ''}`}
        >
            <Icon className={`w-4 h-4 md:w-5 md:h-5 ${isActive ? 'scale-110' : ''}`} />
            <span className="font-bold tracking-wide text-[10px] md:text-sm uppercase">{label}</span>
            {badgeCount > 0 && !isDisabled && (
                <div className="absolute top-1 right-1 flex h-4 w-4 md:h-5 md:w-5 items-center justify-center rounded-full bg-red-600 text-[8px] md:text-[10px] font-black text-white shadow-lg ring-2 ring-stone-900 animate-in zoom-in">
                    {badgeCount}
                </div>
            )}
        </button>
    );
  };

  return (
    <div className="h-[100dvh] w-full bg-stone-950 text-stone-200 flex flex-col overflow-hidden font-sans selection:bg-amber-500/30 animate-in fade-in duration-500 px-safe">

      <div className={`flex flex-col shrink-0 z-30 transition-all duration-500 ease-in-out ${isFullscreenOverlay ? '-translate-y-full h-0 opacity-0 pointer-events-none' : 'translate-y-0 h-auto opacity-100'}`}>
        <Header 
          activeTab={activeTab} 
          onTabChange={setActiveTab} 
          onSettingsClick={() => setIsSettingsOpen(true)}
        />

        <div className="bg-stone-900 border-b border-stone-800 flex items-center relative z-10 overflow-hidden isolate h-11 md:h-14">

          <div 
            className={`absolute left-0 top-0 bottom-0 z-30 w-12 flex items-center transition-all duration-300 transform-gpu ${
                showLeftArrow ? 'opacity-100 scale-100 visible pointer-events-auto' : 'opacity-0 scale-0 invisible pointer-events-none'
            }`}
          >
              <div className="absolute inset-0 bg-gradient-to-r from-stone-900 via-stone-900/90 to-transparent" />
              <button onClick={() => scrollTabs('LEFT')} className="relative h-full w-full flex items-center pl-2 group/arrow" aria-label="Scroll Left">
                <ChevronLeft className="w-5 h-5 text-amber-50 group-hover:scale-125 transition-transform" />
              </button>
          </div>

          <div 
            ref={scrollRef}
            onScroll={updateArrows}
            className="flex overflow-x-auto no-scrollbar flex-1 min-w-0 touch-pan-x scroll-smooth snap-x snap-mandatory overscroll-behavior-x-contain"
          >
            {renderTabButton('FORGE', Anvil, 'Forge')}
            {renderTabButton('DUNGEON', MapIcon, 'Dungeon', completedExpeditionsCount)}
            {renderTabButton('INVENTORY', Package, 'Items')}
            {renderTabButton('MARKET', ShoppingBag, 'Market')}
            {renderTabButton('SHOP', Coins, 'Shop', activeTab !== 'SHOP' ? totalShopVisitors : 0)}
            {renderTabButton('TAVERN', Beer, 'Tavern')}
            {renderTabButton('SIMULATION', Activity, 'Sim')}
          </div>

          <div 
            className={`absolute right-0 top-0 bottom-0 z-30 w-12 flex items-center justify-end transition-all duration-300 transform-gpu ${
                showRightArrow ? 'opacity-100 scale-100 visible pointer-events-auto' : 'opacity-0 scale-0 invisible pointer-events-none'
            }`}
          >
              <div className="absolute inset-0 bg-gradient-to-l from-stone-900 via-stone-900/90 to-transparent" />
              <button onClick={() => scrollTabs('RIGHT')} className="relative h-full w-full flex items-center justify-end pr-2 group/arrow" aria-label="Scroll Right">
                <ChevronRight className="w-5 h-5 text-amber-50 group-hover:scale-125 transition-transform" />
              </button>
          </div>
        </div>
      </div>

      <main className="flex-1 overflow-hidden relative bg-stone-925 flex flex-col min-h-0">
        <div className={`h-full w-full ${activeTab === 'FORGE' ? 'block' : 'hidden'}`}>
            <ForgeTab onNavigate={setActiveTab} />
        </div>
        <div className={`h-full w-full ${activeTab === 'SHOP' ? 'block' : 'hidden'}`}>
            <ShopTab onNavigate={setActiveTab} />
        </div>
        {activeTab === 'INVENTORY' && <InventoryDisplay />}
        {activeTab === 'MARKET' && <MarketTab onNavigate={setActiveTab} />}
        {activeTab === 'TAVERN' && <TavernTab />}
        {activeTab === 'DUNGEON' && < DungeonTab />}
        {activeTab === 'SIMULATION' && <SimulationTab />}
      </main>

      {state.toast?.visible && (
        <div onClick={actions.hideToast} className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[3000] flex items-center gap-3 px-6 py-3 bg-stone-900/95 border border-amber-500/50 text-stone-200 rounded-xl shadow-2xl backdrop-blur-md cursor-pointer animate-in slide-in-from-bottom-4 fade-in duration-300 ring-2 ring-black/50 active:scale-95 w-max max-w-[80vw]">
            <Info className="w-5 h-5 text-amber-500 shrink-0" />
            <span className="text-sm font-bold tracking-tight text-center leading-tight">{state.toast.message}</span>
        </div>
      )}

      <div className="h-[env(safe-area-inset-bottom)] bg-stone-900 shrink-0"></div>

      <TutorialOverlay />
      <EventModal />
      <SleepModal />
      <JournalModal />
      <DungeonResultModal />
      <CraftingResultModal />
      <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} onQuit={onQuit} onLoadRequest={onLoadFromSettings} />
    </div>
  );
};

export default MainGameLayout;

import React, { useState, useEffect, useCallback } from 'react';
import { useGame } from '../context/GameContext';
import { MousePointer2, ChevronRight, Sparkles, X, ScrollText } from 'lucide-react';

const TutorialOverlay: React.FC = () => {
    const { state } = useGame();
    const { tutorialStep } = state;

    const [isVisible, setIsVisible] = useState(false);
    const [lastStep, setLastStep] = useState('');
    const [targetRect, setTargetRect] = useState<DOMRect | null>(null);

    // 대상 요소의 위치를 계산하는 함수
    const updateTargetPosition = useCallback(() => {
        const content = getGuideContent();
