export type RoomType = 'EMPTY' | 'ENTRANCE' | 'BOSS' | 'KEY' | 'WALL' | 'NPC' | 'GOLD' | 'TRAP';

export type TutorialStep = 
    | 'NONE' 
    | 'EVENT_TRIGGERED'
    | 'MARKET_BUY_FURNACE' 
    | 'MARKET_OPEN_CART'
    | 'MARKET_PAY_NOW'
    | 'GO_BACK_FORGE'
    | 'SELECT_BRONZE_SWORD'
    | 'PRESS_START_FORGING'
    | 'MINIGAME_PRESS_HEAT'
    | 'MINIGAME_WAIT_TEMP'
    | 'MINIGAME_PRESS_BELLOWS'
    | 'MINIGAME_TAP_TO_START';

export interface ManualDungeonSession {
    dungeonId: string;
    partyIds: string[];
    grid: RoomType[][];
    visited: boolean[][]; // Fog of war
    playerPos: { x: number, y: number };
    hasKey: boolean;
    isBossLocked: boolean;
    isBossDefeated?: boolean; // New: Tracks if boss was beaten but player is still inside
    npcFound?: boolean; // Track if the NPC in this session was interacted with
    rescuedNpcId?: string; // ID of the NPC rescued during this session
    goldCollected: number; // Cumulative gold found during this session
}

export interface DailyFinancials {
  incomeShop: number;
  incomeInventory: number;
  incomeDungeon: number;
  incomeRepair: number;
  expenseMarket: number;
  expenseWages: number;
  expenseScout: number;
}

export interface PlayerStats {
  gold: number;
  energy: number;
  maxEnergy: number;
  day: number;
  tierLevel: number; // Current crafting/market tier access
  dailyFinancials: DailyFinancials; // Track detailed financial history for the current day
}

export interface ForgeStatus {
  hasFurnace: boolean;
  hasWorkbench: boolean;
  anvilLevel: number;
  isShopOpen: boolean;
}

export interface DungeonResult {
    dungeonName: string;
    rewards: { id: string; name: string; count: number }[];
    goldGained?: number;
    mercenaryResults: {
        id: string;
        name: string;
        job: string;
        levelBefore: number;
        levelAfter: number;
        xpGained: number;
        currentXp: number;
        xpToNext: number;
    }[];
    rescuedMercenary?: Mercenary; // Rescued NPC to be displayed in the result
}

export interface GameToast {
    message: string;
    visible: boolean;
}

export interface GameState {
  stats: PlayerStats;
  inventory: InventoryItem[];
  forge: ForgeStatus;
  activeEvent: GameEvent | null;
  logs: string[]; // For showing history of actions
  knownMercenaries: Mercenary[]; // Tracked regulars and named NPCs

  // Shop System State
  activeCustomer: ShopCustomer | null; // The person currently at the counter
  shopQueue: ShopCustomer[]; // People waiting in line
  visitorsToday: string[]; // List of Mercenary IDs who have visited today
  talkedToToday: string[]; // List of Mercenary IDs who have been talked to today for affinity bonus

  // Market State
  marketStock: Record<string, number>; // Remaining quantity per item ID

  // Game Logic Control
  isCrafting: boolean; // Is the player currently in the minigame?
  showSleepModal: boolean; // Should the End of Day modal be visible?
  showJournal: boolean; // Toggle for the Log/Journal Modal
  toast: GameToast | null; // Global toast notifications

  // Progression
  craftingMastery: Record<string, number>; // Key: Item ID, Value: Craft Count
  unlockedRecipes: string[]; // List of IDs for recipes discovered via gameplay

  // Minigame Persistence
  forgeTemperature: number; // Residual heat from last session
  lastForgeTime: number; // Timestamp of last minigame interaction

  // Dungeon System
  activeExpeditions: Expedition[];
  dungeonClearCounts: Record<string, number>; // Key: Dungeon ID, Value: Count
  dungeonResult: DungeonResult | null; // Populated when claim is clicked to show modal
  activeManualDungeon: ManualDungeonSession | null; // Current manual play session
  showManualDungeonOverlay: boolean; // Toggle for dungeon UI visibility

  // Result Tracking
  lastCraftedItem: InventoryItem | null;

  // Tutorial
  tutorialStep: TutorialStep;

  // UI Effects State
  uiEffects: {
    energyHighlight: boolean;
  };
}

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { useGame } from '../../../context/GameContext';
import {
  Store,
  ShoppingCart,
  ShoppingBag,
  AlertCircle,
  Coins,
  ChevronRight,
  ChevronLeft,
  Trash2,
  Plus,
  Minus,
  Package,
  CreditCard,
} from 'lucide-react';
import { MATERIALS } from '../../../data/materials';
import { MARKET_CATALOG } from '../../../data/market/index';
import { getAssetUrl } from '../../../utils';

interface MarketTabProps {
  onNavigate: (tab: any) => void;
}

const MarketTab: React.FC<MarketTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();

  const [cart, setCart] = useState<Record<string, number>>({});
  const [isCartOpen, setIsCartOpen] = useState(false);

  const [itemMultipliers, setItemMultipliers] = useState<Record<string, number>>({});

  const longPressTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const currentInterval = useRef<number>(200);
  const [pressingItemId, setPressingItemId] = useState<string | null>(null);
  const [removingItemId, setRemovingItemId] = useState<string | null>(null);

  const { hasFurnace, hasWorkbench } = state.forge;
  const currentTier = state.stats.tierLevel;

  const cartItemCount = useMemo(
    () => (Object.values(cart) as number[]).reduce((a, b) => a + b, 0),
    [cart]
  );

  const calculateTotal = () => {
    return Object.entries(cart).reduce((total, [id, count]) => {
      const item = MARKET_CATALOG.find(i => i.id === id);
      return total + (item ? item.price * (count as number) : 0);
    }, 0);
  };

  const totalCost = calculateTotal();

  // Tutorial: Handle Cart Opening
  useEffect(() => {
    if (isCartOpen && state.tutorialStep === 'MARKET_OPEN_CART') {
        actions.setTutorialStep('MARKET_PAY_NOW');
    }
  }, [isCartOpen, state.tutorialStep, actions]);

  const addToCart = (itemId: string, amount: number = 1) => {
    const isOneTimeItem = itemId === 'furnace' || itemId === 'workbench' || itemId.startsWith('scroll_');
    const availableStock = state.marketStock[itemId] || 0;
    const currentInCart = cart[itemId] || 0;

    if (currentInCart >= availableStock) return false;

    const canAddCount = Math.min(amount, availableStock - currentInCart);
    if (canAddCount <= 0) return false;

    // Tutorial Progression: Change to OPEN_CART instead of forcing open
    if (state.tutorialStep === 'MARKET_BUY_FURNACE' && itemId === 'furnace') {
        actions.setTutorialStep('MARKET_OPEN_CART');
    }

    setCart(prev => {
      const nowInCart = prev[itemId] || 0;
      if (nowInCart >= availableStock) return prev;
      if (isOneTimeItem && nowInCart > 0) return prev;

      return {
        ...prev,
        [itemId]: nowInCart + (isOneTimeItem ? 1 : canAddCount),
      };
    });

    return true;
  };

  const removeFromCart = (itemId: string) => {
    let stillHasItems = true;
    setCart(prev => {
      const currentInCart = prev[itemId] || 0;
      if (currentInCart <= 0) {
        stillHasItems = false;
        return prev;
      }

      const newCount = currentInCart - 1;
      const newCart = { ...prev };
      if (newCount <= 0) {
        delete newCart[itemId];
        stillHasItems = false;
      } else {
        newCart[itemId] = newCount;
      }
      return newCart;
    });
    return stillHasItems;
  };

  const deleteFromCart = (itemId: string) => {
    setCart(prev => {
      const newCart = { ...prev };
      delete newCart[itemId];
      return newCart;
    });
  };

  const startContinuousAdd = (itemId: string) => {
    const success = addToCart(itemId, 1);
    if (!success) {
      handleEndLongPress();
      return;
    }
    currentInterval.current = Math.max(50, currentInterval.current * 0.85);
    longPressTimer.current = setTimeout(() => startContinuousAdd(itemId), currentInterval.current);
  };

  const startContinuousRemove = (itemId: string) => {
    const success = removeFromCart(itemId);
    if (!success) {
      handleEndLongPress();
      return;
    }
    currentInterval.current = Math.max(50, currentInterval.current * 0.85);
    longPressTimer.current = setTimeout(() => startContinuousRemove(itemId), currentInterval.current);
  };

  const handleStartLongPress = (e: React.PointerEvent, itemId: string, isRemove: boolean = false) => {
    if (isRemove) setRemovingItemId(itemId);
    else setPressingItemId(itemId);

    currentInterval.current = 220;

    if (isRemove) {
      const success = removeFromCart(itemId);
      if (!success) {
        setRemovingItemId(null);
        return;
      }
    } else {
      const amount = itemMultipliers[itemId] || 1;
      const success = addToCart(itemId, amount);
      if (!success) {
        setPressingItemId(null);
        return;
      }
    }

    longPressTimer.current = setTimeout(() => {
      if (isRemove) startContinuousRemove(itemId);
      else startContinuousAdd(itemId);
    }, 500);
  };

  const handleEndLongPress = () => {
    if (longPressTimer.current) clearTimeout(longPressTimer.current);
    setPressingItemId(null);
    setRemovingItemId(null);
  };

  const handleBuy = () => {
    if (cartItemCount === 0) {
      actions.showToast("Your cart is empty.");
      return;
    }
    if (totalCost > state.stats.gold) {
      actions.showToast("Insufficient Gold!");
      return;
    }

    const itemsToBuy = Object.entries(cart).map(([id, count]) => ({ id, count }));
    const hasFurnaceInPurchase = itemsToBuy.some(i => i.id === 'furnace');

    actions.buyItems(itemsToBuy, totalCost);
    setCart({});
    actions.showToast("Purchase complete!");

    // Tutorial Progression
    if (state.tutorialStep === 'MARKET_PAY_NOW' && hasFurnaceInPurchase) {
        actions.setTutorialStep('GO_BACK_FORGE');
        setIsCartOpen(false);
    }
  };

  const setMultiplier = (itemId: string, mult: number) => {
    setItemMultipliers(prev => ({ ...prev, [itemId]: mult }));
  };

  return (
    <div className="h-full w-full flex bg-stone-950 relative overflow-hidden">
      <div className="flex flex-col h-full w-full relative shrink-0">
        <div className="bg-stone-900/80 backdrop-blur-md p-3 md:p-5 border-b border-stone-800 flex items-center justify-between z-10 shrink-0">
          <div className="flex items-center gap-2 md:gap-4">
            <div className="bg-amber-900/30 p-1.5 md:p-2.5 rounded-xl border border-amber-700/50">
              <Store className="w-4 h-4 md:w-6 md:h-6 text-amber-500" />
            </div>
            <div>
              <h2 className="text-sm md:text-2xl font-black text-stone-100 font-serif tracking-tight uppercase leading-none">
                Market
              </h2>
              <span className="text-[7px] md:text-[9px] font-mono font-bold text-amber-600 block mt-1 uppercase">
                Tier {currentTier} Supplies
              </span>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button
              id="market-pay-btn"
              onClick={handleBuy}
              className={`relative flex items-center gap-2 md:gap-3 px-3 md:px-6 py-1.5 md:py-3 rounded-xl border transition-all shadow-lg active:scale-95 group ${
                cartItemCount === 0
                  ? 'bg-stone-800/40 border-stone-700 text-stone-600 grayscale'
                  : totalCost > state.stats.gold
                    ? 'bg-red-900/40 border-red-700 text-red-300'
                    : 'bg-amber-600 hover:bg-amber-500 border-amber-400 text-white shadow-[0_0_20px_rgba(217,119,6,0.2)]'
              }`}
            >
              <div className="relative">
                <ShoppingCart className={`w-3.5 h-3.5 md:w-5 md:h-5 ${cartItemCount > 0 ? 'animate-bounce' : ''}`} />
                {cartItemCount > 0 && (
                  <div className="absolute -top-2 -right-2 bg-red-600 text-white text-[7px] md:text-[9px] font-black px-1 rounded-full border border-stone-900 ring-1 ring-white/20">
                    {cartItemCount}
                  </div>
                )}
              </div>
              <div className="flex flex-col items-start leading-none">
                <span className="text-[8px] md:text-[10px] font-black uppercase tracking-widest">Pay Now</span>
                <div className="flex items-center gap-0.5 mt-0.5">
                  <span className="text-[9px] md:text-sm font-mono font-black">{totalCost}</span>
                  <Coins className="w-2.5 h-2.5 md:w-3 md:h-3 text-amber-200" />
                </div>
              </div>
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-2 md:p-6 custom-scrollbar pb-24">
          <div className="grid gap-1.5 md:gap-4 max-w-7xl mx-auto content-start grid-cols-5 sm:grid-cols-6 md:grid-cols-8 lg:grid-cols-10">
            {MARKET_CATALOG.map(marketItem => {
              const isKeyItem = marketItem.id === 'furnace' || marketItem.id === 'workbench';
              const isScrollItem = marketItem.id.startsWith('scroll_');
              const isOwned =
                (marketItem.id === 'furnace' && state.forge.hasFurnace) ||
                (marketItem.id === 'workbench' && state.forge.hasWorkbench);

              if (isKeyItem && isOwned) return null;

              let itemName = '';
              let itemTier = 1;
              if (marketItem.id === 'furnace') {
                itemName = 'Furnace';
                itemTier = 0;
              } else if (marketItem.id === 'workbench') {
                itemName = 'Workbench';
                itemTier = 1;
              } else if (marketItem.id === 'scroll_t2') {
                itemName = 'Scroll T2';
                itemTier = 1;
                if (currentTier >= 2) return null;
              } else if (marketItem.id === 'scroll_t3') {
                itemName = 'Scroll T3';
                itemTier = 2;
                if (currentTier >= 3) return null;
              } else {
                const itemDef = Object.values(MATERIALS).find(i => i.id === marketItem.id);
                if (!itemDef) return null;
                itemName = (itemDef as any).name;
                itemTier = (itemDef as any).tier || 1;
              }

              if (itemTier > currentTier) return null;

              const stockLeft = (state.marketStock[marketItem.id] || 0) - (cart[marketItem.id] || 0);
              const isSoldOut = stockLeft <= 0;
              const selectedMult = itemMultipliers[marketItem.id] || 1;
              const invCount = state.inventory.find(i => i.id === marketItem.id)?.quantity || 0;

              // Tutorial Highlight
              const isTutorialTarget = state.tutorialStep === 'MARKET_BUY_FURNACE' && marketItem.id === 'furnace';

              return (
                <div
                  key={marketItem.id}
                  id={marketItem.id === 'furnace' ? 'furnace-item' : undefined}
                  className={`group relative flex flex-col items-center p-1 md:p-2 rounded-lg md:rounded-xl border transition-all h-[130px] md:h-[210px] justify-between overflow-hidden shadow-sm select-none ${
                    pressingItemId === marketItem.id
                      ? 'scale-[0.97] border-amber-500 bg-amber-900/10'
                      : isSoldOut
                        ? 'bg-stone-900 border-stone-800 opacity-60 grayscale'
                        : 'bg-stone-850 border-stone-800'
                  } ${isTutorialTarget ? 'ring-4 ring-amber-500 animate-pulse scale-105 z-50 border-amber-400 bg-amber-950/20' : ''}`}
                >
                  {invCount > 0 && (
                    <div className="absolute top-0.5 left-0.5 px-1 py-0 rounded text-[6px] md:text-[8px] font-black uppercase tracking-tighter border z-10 bg-slate-900/80 border-slate-600 text-slate-300 flex items-center gap-0.5">
                      <Package className="w-1.5 h-1.5 md:w-2 md:h-2" />
                      <span>{invCount}</span>
                    </div>
                  )}

                  <div
                    className={`absolute top-0.5 right-0.5 px-1 py-0 rounded text-[6px] md:text-[8px] font-black uppercase tracking-tighter border z-10 ${
                      stockLeft > 0 ? 'bg-emerald-950/60 border-emerald-500/40 text-emerald-400' : 'bg-red-950/60 border-red-500/40 text-red-500'
                    }`}
                  >
                    {isSoldOut ? 'X' : stockLeft}
                  </div>

                  <div
                    className={`flex-1 w-full flex items-center justify-center transition-all relative mt-1 overflow-hidden rounded-lg
                      ${isSoldOut ? 'cursor-not-allowed' : 'cursor-pointer hover:bg-stone-800/50 group-hover:scale-105 active:scale-95'}
                      touch-none
                    `}
                    onPointerDown={(e) => {
                      if (isSoldOut) return;
                      handleStartLongPress(e, marketItem.id);
                    }}
                    onPointerUp={handleEndLongPress}
                    onPointerLeave={handleEndLongPress}
                    onPointerCancel={handleEndLongPress}
                  >
                    <img
                      src={getAssetUrl(`${marketItem.id}.png`)}
                      className="w-14 h-14 md:w-26 md:h-26 object-contain drop-shadow-md pointer-events-none"
                      onError={(e) => {
                        e.currentTarget.style.display = 'none';
                        e.currentTarget.nextElementSibling?.classList.remove('hidden');
                      }}
                      draggable={false}
                    />
                    <div className="hidden text-base md:text-3xl pointer-events-none">📦</div>
                  </div>

                  {!isSoldOut && !isKeyItem && !isScrollItem && (
                    <div
                      className="multiplier-btn flex items-center gap-0.5 md:gap-1 my-1 bg-stone-950/80 p-0.5 rounded-lg border border-stone-800/50 z-20"
                    >
                      {[1, 5, 10].map(m => (
                        <button
                          key={m}
                          type="button"
                          onClick={(e) => {
                            e.stopPropagation();
                            setMultiplier(marketItem.id, m);
                          }}
                          className={`w-4 h-4 md:w-7 md:h-7 rounded text-[6px] md:text-[9px] font-black transition-all ${
                            selectedMult === m
                              ? 'bg-amber-600 text-white shadow-glow-sm'
                              : 'bg-stone-800 text-stone-500 hover:text-stone-300'
                          }`}
                        >
                          x{m}
                        </button>
                      ))}
                    </div>
                  )}

                  <div className="w-full text-center mb-0.5">
                    <h4
                      className={`text-[7px] md:text-[11px] font-black leading-none truncate px-1 ${
                        isKeyItem || isScrollItem ? 'text-amber-400' : 'text-stone-400'
                      }`}
                    >
                      {itemName}
                    </h4>
                  </div>

                  <div
                    className={`w-full py-0.5 md:py-1 rounded-b-lg border-t flex items-center justify-center gap-0.5 font-mono font-black transition-all
                      text-[7px] md:text-xs
                      ${isSoldOut
                        ? 'bg-stone-900 border-stone-800 text-stone-700 cursor-not-allowed'
                        : 'bg-stone-950 border-stone-800 text-amber-500 cursor-pointer hover:bg-amber-900/20 active:bg-amber-900/40'
                      }
                      select-none touch-none
                    `}
                    onPointerDown={(e) => {
                      if (isSoldOut) return;
                      handleStartLongPress(e, marketItem.id);
                    }}
                    onPointerUp={handleEndLongPress}
                    onPointerLeave={handleEndLongPress}
                    onPointerCancel={handleEndLongPress}
                  >
                    <span className="hidden md:inline pointer-events-none">
                      <Coins className="w-2.5 h-2.5" />
                    </span>
                    <span className="pointer-events-none">{marketItem.price}</span>
                  </div>

                  {isSoldOut && (
                    <div className="absolute inset-0 z-30 flex items-center justify-center bg-black/60 backdrop-blur-[0.5px]">
                      <span className="bg-red-600 text-white text-[6px] md:text-[8px] font-black px-1.5 py-0.5 rounded rotate-12 shadow-md">
                        SOLD
                      </span>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      </div>

      <div
        className={`absolute top-0 right-0 h-full bg-stone-900/95 backdrop-blur-3xl border-l border-stone-800 shadow-[-10px_0_30px_rgba(0,0,0,0.5)] z-[100] flex flex-col transition-all duration-500 ease-in-out ${
          isCartOpen ? 'w-[85%] sm:w-[50%] md:w-80 translate-x-0' : 'w-0 translate-x-full border-none'
        }`}
      >
        <button
          id="market-cart-toggle"
          onClick={() => setIsCartOpen(!isCartOpen)}
          className={`absolute top-1/2 -left-6 md:-left-8 w-6 md:w-8 h-20 md:h-24 -translate-y-1/2 border-y border-l transition-all z-[110] cursor-pointer shadow-xl rounded-l-lg flex flex-col items-center justify-center 
            ${
              cartItemCount > 0
                ? 'bg-amber-600 border-amber-400 animate-pulse text-white shadow-[0_0_20px_rgba(217,119,6,0.3)]'
                : 'bg-stone-800 border-stone-600 text-stone-400 hover:bg-stone-700 hover:text-amber-400'
            } ${state.tutorialStep === 'MARKET_OPEN_CART' ? 'ring-4 ring-amber-500 animate-pulse z-[200]' : ''}`}
        >
          <ShoppingCart className="w-3.5 h-3.5 md:w-5 md:h-5" />
          {isCartOpen ? (
            <ChevronRight className="w-3 h-3 md:w-4 md:h-4 mt-1 opacity-50" />
          ) : (
            <ChevronLeft
              className={`w-3 h-3 md:w-4 md:h-4 mt-1 ${
                cartItemCount > 0 ? 'text-white' : 'text-amber-500 animate-pulse'
              }`}
            />
          )}
        </button>

        <div className={`flex flex-col h-full w-full ${isCartOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
          <div className="bg-stone-850 p-3 md:p-4 border-b border-stone-800 flex items-center justify-between shrink-0">
            <h3 className="font-serif font-black text-xs md:text-lg text-stone-100 uppercase tracking-tighter truncate">
              Your Cart
            </h3>
          </div>

          <div className="flex-1 overflow-y-auto p-2 md:p-3 space-y-2.5 custom-scrollbar">
            {Object.keys(cart).length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-stone-700 text-center px-4">
                <ShoppingBag className="w-8 h-8 md:w-10 md:h-10 opacity-10 mb-2" />
                <p className="italic font-medium text-[8px] md:text-[10px] uppercase tracking-widest">Cart is empty</p>
              </div>
            ) : (
              Object.entries(cart).map(([id, count]) => {
                const marketItem = MARKET_CATALOG.find(i => i.id === id);
                const name =
                  id === 'furnace'
                    ? 'Furnace'
                    : id === 'workbench'
                      ? 'Workbench'
                      : MATERIALS[id.toUpperCase() as keyof typeof MATERIALS]?.name || id;

                if (!marketItem) return null;

                return (
                  <div key={id} className="flex items-center gap-2 bg-stone-950 p-2 md:p-3 rounded-xl border border-stone-800 group select-none">
                    <div className="w-10 h-10 md:w-14 md:h-14 bg-stone-900 rounded-lg border border-stone-800 flex items-center justify-center shrink-0">
                      <img src={getAssetUrl(`${id}.png`)} className="w-8 h-8 md:w-11 md:h-11 object-contain" draggable={false} />
                    </div>
                    <div className="flex-1 min-w-0 flex flex-col justify-center">
                      <div className="text-stone-100 font-bold text-[10px] md:text-sm truncate">{name}</div>
                      <div className="text-amber-600 font-mono text-[9px] md:text-xs font-bold">{marketItem.price * (count as number)} G</div>
                    </div>
                    <div className="flex items-center gap-1.5 shrink-0 bg-stone-900 rounded-lg border border-stone-700 p-0.5">
                      <button
                        type="button"
                        onClick={() => removeFromCart(id)}
                        className="w-5 h-5 md:w-7 md:h-7 flex items-center justify-center bg-stone-800 hover:bg-stone-700 text-stone-400 rounded transition-all"
                      >
                        <Minus className="w-2.5 h-2.5" />
                      </button>
                      <span className="min-w-[16px] text-center font-mono text-stone-200 font-bold text-[10px] md:text-xs">{count}</span>
                      <button
                        type="button"
                        onClick={() => addToCart(id, 1)}
                        className="w-5 h-5 md:w-7 md:h-7 flex items-center justify-center bg-stone-800 hover:bg-stone-700 text-stone-400 rounded transition-all"
                      >
                        <Plus className="w-2.5 h-2.5" />
                      </button>
                    </div>
                    <button type="button" onClick={() => deleteFromCart(id)} className="p-1 md:p-1.5 hover:text-red-500 transition-colors">
                      <Trash2 className="w-3 h-3 md:w-4 md:h-4" />
                    </button>
                  </div>
                );
              })
            )}
          </div>

          <div className="bg-stone-850 p-3 md:p-4 border-t border-stone-800 space-y-3 shrink-0">
            <div className="flex justify-between items-center text-[9px] md:text-sm text-stone-600 font-bold uppercase tracking-tighter">
              <span>Grand Total</span>
              <span className={`text-sm md:text-xl font-mono font-black ${totalCost > state.stats.gold ? 'text-red-500' : 'text-amber-500'}`}>
                {totalCost} G
              </span>
            </div>
            <button
              id="cart-purchase-btn"
              type="button"
              onClick={handleBuy}
              className={`w-full py-2.5 md:py-3 rounded-xl font-black text-xs md:text-sm transition-all flex items-center justify-center gap-2 shadow-xl ${
                totalCost > state.stats.gold ? 'bg-stone-800 text-stone-300' : 
                totalCost === 0 ? 'bg-stone-800 text-stone-500 grayscale opacity-60' :
                'bg-amber-600 hover:bg-amber-500 text-white'
              } ${state.tutorialStep === 'MARKET_PAY_NOW' ? 'ring-4 ring-amber-500 animate-pulse scale-105 z-50' : ''}`}
            >
              <ShoppingBag className="w-4 h-4" />
              <span>{totalCost > state.stats.gold ? 'Insufficient Funds' : 'Purchase'}</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default MarketTab;

import React, { useState, useEffect, useCallback } from 'react';
import { useGame } from '../context/GameContext';
import { MousePointer2, ChevronRight, Sparkles, X, ScrollText } from 'lucide-react';

const TutorialOverlay: React.FC = () => {
    const { state } = useGame();
    const { tutorialStep } = state;

    const [isVisible, setIsVisible] = useState(false);
    const [lastStep, setLastStep] = useState('');
    const [targetRect, setTargetRect] = useState<DOMRect | null>(null);

    // 대상 요소의 위치를 계산하는 함수
    const updateTargetPosition = useCallback(() => {
        const content = getGuideContent();
        if (content?.target) {
            const el = document.getElementById(content.target);
            if (el) {
                setTargetRect(el.getBoundingClientRect());
                return;
            }
        }
        setTargetRect(null);
    }, [tutorialStep]);

    useEffect(() => {
        if (tutorialStep !== 'NONE' && tutorialStep !== lastStep) {
            setIsVisible(true);
            setLastStep(tutorialStep);

            // 단계 변경 시 즉시 위치 계산
            setTimeout(updateTargetPosition, 100);

            const displayTime = tutorialStep === 'EVENT_TRIGGERED' ? 12000 : 8000;
            const timer = setTimeout(() => {
                setIsVisible(false);
            }, displayTime);

            return () => clearTimeout(timer);
        }
    }, [tutorialStep, lastStep, updateTargetPosition]);

    // 화면 리사이즈나 스크롤 시 위치 재계산
    useEffect(() => {
        if (!isVisible) return;

        window.addEventListener('resize', updateTargetPosition);
        const interval = setInterval(updateTargetPosition, 500); // 주기적 체크 (애니메이션 등 대응)

        return () => {
            window.removeEventListener('resize', updateTargetPosition);
            clearInterval(interval);
        };
    }, [isVisible, updateTargetPosition]);

    if (tutorialStep === 'NONE') return null;

    const getGuideContent = () => {
        switch (tutorialStep) {
            case 'EVENT_TRIGGERED':
                return {
                    title: "A Ruined Legacy",
                    text: "You stand amidst the cold ashes of Lockhart's Forge. To restore your family's name, you must first visit the market.",
                    target: "tab-MARKET"
                };
            case 'MARKET_BUY_FURNACE':
                return {
                    title: "Essential Equipment",
                    text: "The merchant has a basic Furnace for 500 Gold. Click on it to prepare for installation.",
                    target: "furnace-item"
                };
            case 'MARKET_OPEN_CART':
                return {
                    title: "Review Your Order",
                    text: "Item added to cart! Click the cart icon on the right to review your items.",
                    target: "market-cart-toggle"
                };
            case 'MARKET_PAY_NOW':
                return {
                    title: "Finalize Transaction",
                    text: "You have the funds. Click 'Purchase' in your cart to have the equipment delivered to your forge.",
                    target: "cart-purchase-btn"
                };
            case 'GO_BACK_FORGE':
                return {
                    title: "The Fire Returns",
                    text: "Installation complete! Now, head back to the Forge tab to begin your first project.",
                    target: "tab-FORGE"
                };
            case 'SELECT_BRONZE_SWORD':
                return {
                    title: "Choose a Pattern",
                    text: "Select the Bronze Shortsword recipe. It is the perfect starting point.",
                    target: "sword_bronze_t1-item"
                };
            case 'PRESS_START_FORGING':
                return {
                    title: "Ready the Anvil",
                    text: "You have the materials. Click 'Start Forging' to enter the inner chamber.",
                    target: "start-forging-btn"
                };
            case 'MINIGAME_PRESS_HEAT':
                return {
                    title: "Master the Heat",
                    text: "Metal requires heat to be shaped. Click the 'HEAT' button to stoke the embers.",
                    target: null 
                };
            case 'MINIGAME_WAIT_TEMP':
                return {
                    title: "Observe the Glow",
                    text: "Wait until the metal cools to a workable temperature of 450°C.",
                    target: null
                };
            case 'MINIGAME_PRESS_BELLOWS':
                return {
                    title: "Keep the Spark Alive",
                    text: "The fire is dying! Rapidly click 'PUMP' to boost the temperature.",
                    target: null
                };
            case 'MINIGAME_TAP_TO_START':
                return {
                    title: "Strike while Hot",
                    text: "The metal glows white! Tap anywhere on the anvil area to begin.",
                    target: null
                };
            default:
                return null;
        }
    };

    const content = getGuideContent();
    if (!content || !isVisible) return null;

    return (
        <div className="fixed inset-0 z-[4000] pointer-events-none overflow-hidden select-none">
            {/* 1. 안내 메시지 박스 (화면 정중앙 고정) */}
            <div 
                className={`absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 w-[90%] max-w-sm bg-stone-900/95 backdrop-blur-xl border-2 border-amber-500 rounded-3xl shadow-[0_0_80px_rgba(0,0,0,0.95)] p-8 flex flex-col items-center text-center animate-in zoom-in-95 fade-in duration-500 pointer-events-auto cursor-pointer active:scale-95 transition-transform`}
                onClick={() => setIsVisible(false)}
            >
                <div className="absolute top-4 right-4 text-stone-600">
                    <X className="w-5 h-5" />
                </div>

                <div className="bg-amber-900/40 p-3 rounded-2xl border border-amber-700/50 mb-4 shadow-inner">
                    {tutorialStep === 'EVENT_TRIGGERED' ? (
                        <ScrollText className="w-6 h-6 text-amber-500 animate-pulse" />
                    ) : (
                        <Sparkles className="w-6 h-6 text-amber-400 animate-pulse" />
                    )}
                </div>

                <h3 className="text-xl font-black text-amber-100 font-serif uppercase tracking-tight mb-3 drop-shadow-md">
                    {content.title}
                </h3>

                <p className="text-stone-300 text-sm md:text-base leading-relaxed mb-6 italic px-2">
                    "{content.text}"
                </p>

                <div className="flex items-center gap-2 text-stone-600 font-black uppercase text-[10px] tracking-[0.2em] opacity-80">
                    <span>Click to continue</span>
                    <ChevronRight className="w-4 h-4" />
                </div>
            </div>

            {/* 2. 동적 지시 포인터 (대상 요소 위에 표시) */}
            {targetRect && (
                <div 
                    className="fixed z-[4001] pointer-events-none transition-all duration-300 ease-out"
                    style={{
                        top: targetRect.top + targetRect.height / 2,
                        left: targetRect.left + targetRect.width / 2,
                        transform: 'translate(-50%, -50%)'
                    }}
                >
                    {/* 대상 요소를 감싸는 하이라이트 박스 */}
                    <div 
                        className="absolute inset-0 border-2 border-amber-400 rounded-lg animate-pulse shadow-[0_0_30px_rgba(245,158,11,0.8)]"
                        style={{
                            width: targetRect.width + 12,
                            height: targetRect.height + 12,
                            transform: 'translate(-50%, -50%)'
                        }}
                    ></div>

                    {/* 지시 마우스 아이콘 */}
                    <div className="absolute top-full left-full mt-2 animate-bounce">
                        <MousePointer2 
                            className="w-12 h-12 text-amber-400 drop-shadow-[0_0_20px_rgba(245,158,11,1)] fill-amber-500/30" 
                            style={{ transform: 'rotate(-15deg)' }}
                        />
                    </div>
                </div>
            )}
        </div>
    );
};

export default TutorialOverlay;

import { InventoryItem } from './inventory';
import { GameEvent } from './events';
import { ShopCustomer } from './shop';
import { Mercenary } from '../models/Mercenary';
import { Expedition } from '../models/Dungeon';

export type RoomType = 'EMPTY' | 'ENTRANCE' | 'BOSS' | 'KEY' | 'WALL' | 'NPC' | 'GOLD' | 'TRAP';

export type TutorialStep = 
    | 'NONE' 
    | 'EVENT_TRIGGERED'
    | 'MARKET_SCROLL_TABS'
    | 'MARKET_BUY_FURNACE' 
    | 'MARKET_OPEN_CART'
    | 'MARKET_PAY_NOW'
    | 'GO_BACK_FORGE'
    | 'SELECT_BRONZE_SWORD'
    | 'PRESS_START_FORGING'
    | 'MINIGAME_PRESS_HEAT'
    | 'MINIGAME_WAIT_TEMP'
    | 'MINIGAME_PRESS_BELLOWS'
    | 'MINIGAME_TAP_TO_START';

export interface ManualDungeonSession {
    dungeonId: string;
    partyIds: string[];
    grid: RoomType[][];
    visited: boolean[][]; // Fog of war
    playerPos: { x: number, y: number };
    hasKey: boolean;
    isBossLocked: boolean;
    isBossDefeated?: boolean; // New: Tracks if boss was beaten but player is still inside
    npcFound?: boolean; // Track if the NPC in this session was interacted with
    rescuedNpcId?: string; // ID of the NPC rescued during this session
    goldCollected: number; // Cumulative gold found during this session
}

export interface DailyFinancials {
  incomeShop: number;
  incomeInventory: number;
  incomeDungeon: number;
  incomeRepair: number;
  expenseMarket: number;
  expenseWages: number;
  expenseScout: number;
}

export interface PlayerStats {
  gold: number;
  energy: number;
  maxEnergy: number;
  day: number;
  tierLevel: number; // Current crafting/market tier access
  dailyFinancials: DailyFinancials; // Track detailed financial history for the current day
}

export interface ForgeStatus {
  hasFurnace: boolean;
  hasWorkbench: boolean;
  anvilLevel: number;
  isShopOpen: boolean;
}

export interface DungeonResult {
    dungeonName: string;
    rewards: { id: string; name: string; count: number }[];
    goldGained?: number;
    mercenaryResults: {
        id: string;
        name: string;
        job: string;
        levelBefore: number;
        levelAfter: number;
        xpGained: number;
        currentXp: number;
        xpToNext: number;
    }[];
    rescuedMercenary?: Mercenary; // Rescued NPC to be displayed in the result
}

export interface GameToast {
    message: string;
    visible: boolean;
}

export interface GameState {
  stats: PlayerStats;
  inventory: InventoryItem[];
  forge: ForgeStatus;
  activeEvent: GameEvent | null;
  logs: string[]; // For showing history of actions
  knownMercenaries: Mercenary[]; // Tracked regulars and named NPCs

  // Shop System State
  activeCustomer: ShopCustomer | null; // The person currently at the counter
  shopQueue: ShopCustomer[]; // People waiting in line
  visitorsToday: string[]; // List of Mercenary IDs who have visited today
  talkedToToday: string[]; // List of Mercenary IDs who have been talked to today for affinity bonus

  // Market State
  marketStock: Record<string, number>; // Remaining quantity per item ID

  // Game Logic Control
  isCrafting: boolean; // Is the player currently in the minigame?
  showSleepModal: boolean; // Should the End of Day modal be visible?
  showJournal: boolean; // Toggle for the Log/Journal Modal
  toast: GameToast | null; // Global toast notifications

  // Progression
  craftingMastery: Record<string, number>; // Key: Item ID, Value: Craft Count
  unlockedRecipes: string[]; // List of IDs for recipes discovered via gameplay

  // Minigame Persistence
  forgeTemperature: number; // Residual heat from last session
  lastForgeTime: number; // Timestamp of last minigame interaction

  // Dungeon System
  activeExpeditions: Expedition[];
  dungeonClearCounts: Record<string, number>; // Key: Dungeon ID, Value: Count
  dungeonResult: DungeonResult | null; // Populated when claim is clicked to show modal
  activeManualDungeon: ManualDungeonSession | null; // Current manual play session
  showManualDungeonOverlay: boolean; // Toggle for dungeon UI visibility

  // Result Tracking
  lastCraftedItem: InventoryItem | null;

  // Tutorial
  tutorialStep: TutorialStep;

  // UI Effects State
  uiEffects: {
    energyHighlight: boolean;
  };
}

import React, { useState, useRef, useEffect, useCallback, useLayoutEffect } from 'react';
import Header from './Header';
import { InventoryDisplay } from './InventoryDisplay';
import { Anvil, Package, ShoppingBag, Coins, Beer, Map as MapIcon, Activity, Info, ChevronLeft, ChevronRight } from 'lucide-react';
import { useGame } from '../context/GameContext';

// Import Background Services
import { useShopService } from '../services/shop/shop-service';
import { useDungeonService } from '../services/dungeon/dungeon-service';

// Import Tabs
import ForgeTab from './tabs/Forge/ForgeTab';
import ShopTab from './tabs/Shop/ShopTab';
import TavernTab from './tabs/Tavern/TavernTab';
import MarketTab from './tabs/Market/MarketTab';
import DungeonTab from './tabs/Dungeon/DungeonTab';
import SimulationTab from './tabs/Simulation/SimulationTab';

// Import Modals
import EventModal from './modals/EventModal';
import SleepModal from './modals/SleepModal';
import JournalModal from './modals/JournalModal';
import DungeonResultModal from './modals/DungeonResultModal';
import CraftingResultModal from './modals/CraftingResultModal';
import SettingsModal from './modals/SettingsModal';
import TutorialOverlay from './TutorialOverlay';

interface MainGameLayoutProps {
    onQuit: () => void;
    onLoadFromSettings: (data: any, index: number) => void;
}

const MainGameLayout: React.FC<MainGameLayoutProps> = ({ onQuit, onLoadFromSettings }) => {
  const [activeTab, setActiveTab] = useState<'FORGE' | 'INVENTORY' | 'MARKET' | 'SHOP' | 'TAVERN' | 'DUNGEON' | 'SIMULATION'>('FORGE');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const { state, actions } = useGame();

  const { tutorialStep } = state;

  // Tutorial Auto-Navigation & Visibility Check
  useEffect(() => {
    if (tutorialStep === 'MARKET_BUY_FURNACE' && activeTab !== 'MARKET') {
        setActiveTab('MARKET');
    } else if (tutorialStep === 'EVENT_TRIGGERED' && activeTab === 'MARKET') {
        actions.setTutorialStep('MARKET_BUY_FURNACE');
    }

    // 모바일 세로모드 대응: Market 탭이 가려져 있는지 체크
    if (tutorialStep === 'EVENT_TRIGGERED' && activeTab === 'FORGE') {
        const marketTab = document.getElementById('tab-MARKET');
        const scrollContainer = scrollRef.current;
        if (marketTab && scrollContainer) {
            const tabRect = marketTab.getBoundingClientRect();
            const containerRect = scrollContainer.getBoundingClientRect();
            // 탭의 오른쪽 끝이 컨테이너의 가용 범위를 벗어났다면 스크롤 유도 단계로 전환
            if (tabRect.right > containerRect.right - 10) {
                actions.setTutorialStep('MARKET_SCROLL_TABS');
            }
        }
    }
  }, [tutorialStep, activeTab, actions]);

  // Scroll visibility logic
  const scrollRef = useRef<HTMLDivElement>(null);
  const [showLeftArrow, setShowLeftArrow] = useState(false);
  const [showRightArrow, setShowRightArrow] = useState(false);

  const updateArrows = useCallback(() => {
    if (scrollRef.current) {
      const { scrollLeft, scrollWidth, clientWidth } = scrollRef.current;
      const canScroll = scrollWidth > clientWidth + 2;
      setShowLeftArrow(canScroll && scrollLeft > 1);
      const isAtEnd = Math.ceil(scrollLeft) >= (scrollWidth - clientWidth - 2);
      setShowRightArrow(canScroll && !isAtEnd);

      // 스크롤 시 Market 탭이 보이기 시작하면 단계 복구
      if (state.tutorialStep === 'MARKET_SCROLL_TABS') {
          const marketTab = document.getElementById('tab-MARKET');
          if (marketTab) {
              const tabRect = marketTab.getBoundingClientRect();
              const containerRect = scrollRef.current.getBoundingClientRect();
              if (tabRect.right <= containerRect.right) {
                  actions.setTutorialStep('EVENT_TRIGGERED');
              }
          }
      }
    }
  }, [state.tutorialStep, actions]);

  const scrollTabs = (direction: 'LEFT' | 'RIGHT') => {
    if (scrollRef.current) {
      const amount = direction === 'LEFT' ? -200 : 200;
      scrollRef.current.scrollBy({ left: amount, behavior: 'smooth' });
    }
  };

  useLayoutEffect(() => {
    const timer = setTimeout(updateArrows, 100);
    return () => clearTimeout(timer);
  }, [updateArrows, activeTab]);

  useEffect(() => {
    window.addEventListener('resize', updateArrows);
    return () => window.removeEventListener('resize', updateArrows);
  }, [updateArrows]);

  useShopService();
  useDungeonService();

  const completedExpeditionsCount = state.activeExpeditions.filter(
      exp => exp.status === 'COMPLETED'
  ).length;

  const totalShopVisitors = (state.activeCustomer ? 1 : 0) + state.shopQueue.length;
  const isFullscreenOverlay = state.isCrafting || (state.activeManualDungeon && state.showManualDungeonOverlay);

  const renderTabButton = (id: typeof activeTab, Icon: any, label: string, badgeCount: number = 0) => {
    const isActive = activeTab === id;

    // Tutorial Targeting Logic
    const isMarketPhase = ['EVENT_TRIGGERED', 'MARKET_SCROLL_TABS', 'MARKET_BUY_FURNACE', 'MARKET_PAY_NOW'].includes(tutorialStep);
    const isForgePhase = ['GO_BACK_FORGE', 'SELECT_BRONZE_SWORD', 'PRESS_START_FORGING'].includes(tutorialStep) || tutorialStep.startsWith('MINIGAME_');

    const isTutorialTarget = (isMarketPhase && id === 'MARKET') || (isForgePhase && id === 'FORGE');

    // Disable other tabs during tutorial
    const isTutorialActive = tutorialStep !== 'NONE';
    const isDisabled = isTutorialActive && !isTutorialTarget;

    return (
        <button 
            id={`tab-${id}`}
            onClick={() => !isDisabled && setActiveTab(id)}
            disabled={isDisabled}
            className={`relative flex items-center gap-2 px-5 md:px-6 py-3 md:py-4 border-b-2 transition-all whitespace-nowrap snap-start shrink-0 ${
                isActive 
                ? 'border-amber-500 text-amber-500 bg-stone-800/60 z-10' 
                : 'border-transparent text-stone-500 hover:text-stone-300 hover:bg-stone-800/30'
            } ${isTutorialTarget ? 'ring-2 ring-amber-500 animate-pulse bg-amber-900/20' : ''} ${isDisabled ? 'opacity-30 cursor-not-allowed grayscale' : ''}`}
        >
            <Icon className={`w-4 h-4 md:w-5 md:h-5 ${isActive ? 'scale-110' : ''}`} />
            <span className="font-bold tracking-wide text-[10px] md:text-sm uppercase">{label}</span>
            {badgeCount > 0 && !isDisabled && (
                <div className="absolute top-1 right-1 flex h-4 w-4 md:h-5 md:w-5 items-center justify-center rounded-full bg-red-600 text-[8px] md:text-[10px] font-black text-white shadow-lg ring-2 ring-stone-900 animate-in zoom-in">
                    {badgeCount}
                </div>
            )}
        </button>
    );
  };

  return (
    <div className="h-[100dvh] w-full bg-stone-950 text-stone-200 flex flex-col overflow-hidden font-sans selection:bg-amber-500/30 animate-in fade-in duration-500 px-safe">

      <div className={`flex flex-col shrink-0 z-30 transition-all duration-500 ease-in-out ${isFullscreenOverlay ? '-translate-y-full h-0 opacity-0 pointer-events-none' : 'translate-y-0 h-auto opacity-100'}`}>
        <Header 
          activeTab={activeTab} 
          onTabChange={setActiveTab} 
          onSettingsClick={() => setIsSettingsOpen(true)}
        />

        <div className="bg-stone-900 border-b border-stone-800 flex items-center relative z-10 overflow-hidden isolate h-11 md:h-14">

          <div 
            className={`absolute left-0 top-0 bottom-0 z-30 w-12 flex items-center transition-all duration-300 transform-gpu ${
                showLeftArrow ? 'opacity-100 scale-100 visible pointer-events-auto' : 'opacity-0 scale-0 invisible pointer-events-none'
            }`}
          >
              <div className="absolute inset-0 bg-gradient-to-r from-stone-900 via-stone-900/90 to-transparent" />
              <button onClick={() => scrollTabs('LEFT')} className="relative h-full w-full flex items-center pl-2 group/arrow" aria-label="Scroll Left">
                <ChevronLeft className="w-5 h-5 text-amber-50 group-hover:scale-125 transition-transform" />
              </button>
          </div>

          <div 
            ref={scrollRef}
            onScroll={updateArrows}
            className="flex overflow-x-auto no-scrollbar flex-1 min-w-0 touch-pan-x scroll-smooth snap-x snap-mandatory overscroll-behavior-x-contain"
          >
            {renderTabButton('FORGE', Anvil, 'Forge')}
            {renderTabButton('DUNGEON', MapIcon, 'Dungeon', completedExpeditionsCount)}
            {renderTabButton('INVENTORY', Package, 'Items')}
            {renderTabButton('MARKET', ShoppingBag, 'Market')}
            {renderTabButton('SHOP', Coins, 'Shop', activeTab !== 'SHOP' ? totalShopVisitors : 0)}
            {renderTabButton('TAVERN', Beer, 'Tavern')}
            {renderTabButton('SIMULATION', Activity, 'Sim')}
          </div>

          <div 
            className={`absolute right-0 top-0 bottom-0 z-30 w-12 flex items-center justify-end transition-all duration-300 transform-gpu ${
                showRightArrow ? 'opacity-100 scale-100 visible pointer-events-auto' : 'opacity-0 scale-0 invisible pointer-events-none'
            }`}
          >
              <div className="absolute inset-0 bg-gradient-to-l from-stone-900 via-stone-900/90 to-transparent" />
              <button 
                id="tab-scroll-right"
                onClick={() => scrollTabs('RIGHT')} 
                className="relative h-full w-full flex items-center justify-end pr-2 group/arrow" 
                aria-label="Scroll Right"
              >
                <ChevronRight className="w-5 h-5 text-amber-50 group-hover:scale-125 transition-transform" />
              </button>
          </div>
        </div>
      </div>

      <main className="flex-1 overflow-hidden relative bg-stone-925 flex flex-col min-h-0">
        <div className={`h-full w-full ${activeTab === 'FORGE' ? 'block' : 'hidden'}`}>
            <ForgeTab onNavigate={setActiveTab} />
        </div>
        <div className={`h-full w-full ${activeTab === 'SHOP' ? 'block' : 'hidden'}`}>
            <ShopTab onNavigate={setActiveTab} />
        </div>
        {activeTab === 'INVENTORY' && <InventoryDisplay />}
        {activeTab === 'MARKET' && <MarketTab onNavigate={setActiveTab} />}
        {activeTab === 'TAVERN' && <TavernTab />}
        {activeTab === 'DUNGEON' && < DungeonTab />}
        {activeTab === 'SIMULATION' && <SimulationTab />}
      </main>

      {state.toast?.visible && (
        <div onClick={actions.hideToast} className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[3000] flex items-center gap-3 px-6 py-3 bg-stone-900/95 border border-amber-500/50 text-stone-200 rounded-xl shadow-2xl backdrop-blur-md cursor-pointer animate-in slide-in-from-bottom-4 fade-in duration-300 ring-2 ring-black/50 active:scale-95 w-max max-w-[80vw]">
            <Info className="w-5 h-5 text-amber-500 shrink-0" />
            <span className="text-sm font-bold tracking-tight text-center leading-tight">{state.toast.message}</span>
        </div>
      )}

      <div className="h-[env(safe-area-inset-bottom)] bg-stone-900 shrink-0"></div>

      <TutorialOverlay />
      <EventModal />
      <SleepModal />
      <JournalModal />
      <DungeonResultModal />
      <CraftingResultModal />
      <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} onQuit={onQuit} onLoadRequest={onLoadFromSettings} />
    </div>
  );
};

export default MainGameLayout;

import React, { useState, useEffect, useCallback } from 'react';
import { useGame } from '../context/GameContext';
import { MousePointer2, ChevronRight, Sparkles, X, ScrollText } from 'lucide-react';

const TutorialOverlay: React.FC = () => {
    const { state } = useGame();
    const { tutorialStep } = state;

    const [isVisible, setIsVisible] = useState(false);
    const [lastStep, setLastStep] = useState('');
    const [targetRect, setTargetRect] = useState<DOMRect | null>(null);

    // 대상 요소의 위치를 계산하는 함수
    const updateTargetPosition = useCallback(() => {
        const content = getGuideContent();
        if (content?.target) {
            const el = document.getElementById(content.target);
            if (el) {
                setTargetRect(el.getBoundingClientRect());
                return;
            }
        }
        setTargetRect(null);
    }, [tutorialStep]);

    useEffect(() => {
        if (tutorialStep !== 'NONE' && tutorialStep !== lastStep) {
            setIsVisible(true);
            setLastStep(tutorialStep);

            // 단계 변경 시 즉시 위치 계산
            setTimeout(updateTargetPosition, 100);

            const displayTime = (tutorialStep === 'EVENT_TRIGGERED' || tutorialStep === 'MARKET_SCROLL_TABS') ? 12000 : 8000;
            const timer = setTimeout(() => {
                setIsVisible(false);
            }, displayTime);

            return () => clearTimeout(timer);
        }
    }, [tutorialStep, lastStep, updateTargetPosition]);

    // 화면 리사이즈나 스크롤 시 위치 재계산
    useEffect(() => {
        if (!isVisible) return;

        window.addEventListener('resize', updateTargetPosition);
        const interval = setInterval(updateTargetPosition, 500); // 주기적 체크 (애니메이션 등 대응)

        return () => {
            window.removeEventListener('resize', updateTargetPosition);
            clearInterval(interval);
        };
    }, [isVisible, updateTargetPosition]);

    if (tutorialStep === 'NONE') return null;

    const getGuideContent = () => {
        switch (tutorialStep) {
            case 'EVENT_TRIGGERED':
                return {
                    title: "A Ruined Legacy",
                    text: "You stand amidst the cold ashes of Lockhart's Forge. To restore your family's name, you must first visit the market.",
                    target: "tab-MARKET"
                };
            case 'MARKET_SCROLL_TABS':
                return {
                    title: "Hidden Commerce",
                    text: "The market tab is currently hidden. Click the arrow button to scroll the navigation bar.",
                    target: "tab-scroll-right"
                };
            case 'MARKET_BUY_FURNACE':
                return {
                    title: "Essential Equipment",
                    text: "The merchant has a basic Furnace for 500 Gold. Click on it to prepare for installation.",
                    target: "furnace-item"
                };
            case 'MARKET_OPEN_CART':
                return {
                    title: "Review Your Order",
                    text: "Item added to cart! Click the cart icon on the right to review your items.",
                    target: "market-cart-toggle"
                };
            case 'MARKET_PAY_NOW':
                return {
                    title: "Finalize Transaction",
                    text: "You have the funds. Click 'Purchase' in your cart to have the equipment delivered to your forge.",
                    target: "cart-purchase-btn"
                };
            case 'GO_BACK_FORGE':
                return {
                    title: "The Fire Returns",
                    text: "Installation complete! Now, head back to the Forge tab to begin your first project.",
                    target: "tab-FORGE"
                };
            case 'SELECT_BRONZE_SWORD':
                return {
                    title: "Choose a Pattern",
                    text: "Select the Bronze Shortsword recipe. It is the perfect starting point.",
                    target: "sword_bronze_t1-item"
                };
            case 'PRESS_START_FORGING':
                return {
                    title: "Ready the Anvil",
                    text: "You have the materials. Click 'Start Forging' to enter the inner chamber.",
                    target: "start-forging-btn"
                };
            case 'MINIGAME_PRESS_HEAT':
                return {
                    title: "Master the Heat",
                    text: "Metal requires heat to be shaped. Click the 'HEAT' button to stoke the embers.",
                    target: null 
                };
            case 'MINIGAME_WAIT_TEMP':
                return {
                    title: "Observe the Glow",
                    text: "Wait until the metal cools to a workable temperature of 450°C.",
                    target: null
                };
            case 'MINIGAME_PRESS_BELLOWS':
                return {
                    title: "Keep the Spark Alive",
                    text: "The fire is dying! Rapidly click 'PUMP' to boost the temperature.",
                    target: null
                };
            case 'MINIGAME_TAP_TO_START':
                return {
                    title: "Strike while Hot",
                    text: "The metal glows white! Tap anywhere on the anvil area to begin.",
                    target: null
                };
            default:
                return null;
        }
    };

    const content = getGuideContent();
    if (!content || !isVisible) return null;

    return (
        <div className="fixed inset-0 z-[4000] pointer-events-none overflow-hidden select-none">
            {/* 1. 안내 메시지 박스 (화면 정중앙 고정) */}
            <div 
                className={`absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 w-[90%] max-w-sm bg-stone-900/95 backdrop-blur-xl border-2 border-amber-500 rounded-3xl shadow-[0_0_80px_rgba(0,0,0,0.95)] p-8 flex flex-col items-center text-center animate-in zoom-in-95 fade-in duration-500 pointer-events-auto cursor-pointer active:scale-95 transition-transform`}
                onClick={() => setIsVisible(false)}
            >
                <div className="absolute top-4 right-4 text-stone-600">
                    <X className="w-5 h-5" />
                </div>

                <div className="bg-amber-900/40 p-3 rounded-2xl border border-amber-700/50 mb-4 shadow-inner">
